import{_ as s,o as e,c as n,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"按业务领域组织模块：让变化沿用例而不是文件类型聚合","description":"","frontmatter":{"title":"按业务领域组织模块：让变化沿用例而不是文件类型聚合","stage":"intermediate","direction":"frontend","tags":["architecture","domain-modules","modularity"]},"headers":[],"relativePath":"01-frontend/notes/application-architecture/14-organize-by-domain.md","filePath":"01-frontend/notes/application-architecture/14-organize-by-domain.md","lastUpdated":1784382391000}'),t={name:"01-frontend/notes/application-architecture/14-organize-by-domain.md"};function l(r,a,p,d,o,h){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="按业务领域组织模块-让变化沿用例而不是文件类型聚合" tabindex="-1">按业务领域组织模块：让变化沿用例而不是文件类型聚合 <a class="header-anchor" href="#按业务领域组织模块-让变化沿用例而不是文件类型聚合" aria-label="Permalink to &quot;按业务领域组织模块：让变化沿用例而不是文件类型聚合&quot;">​</a></h1><p>领域模块以一组共同变化的业务规则为边界，并通过公开入口提供用例、事件和稳定类型。模块内部仍可按 UI、application、domain 与 infrastructure 分层，但这些技术子层不能成为全仓库任意导入的全局目录。</p><h2 id="前置知识与能力边界" tabindex="-1">前置知识与能力边界 <a class="header-anchor" href="#前置知识与能力边界" aria-label="Permalink to &quot;前置知识与能力边界&quot;">​</a></h2><ul><li><a href="./01-single-responsibility-composition">单一职责与组合</a></li><li><a href="./02-controlled-uncontrolled">Controlled 与 Uncontrolled</a></li><li>React State、Context、Effect 与 TypeScript 判别联合</li><li>浏览器事件、HTTP 和可访问性基础</li></ul><p>本文处理前端模块切分、公开入口和所有权；完整领域驱动设计战术模式不是前置要求。</p><h2 id="_1-定义、所有权与数据流" tabindex="-1">1. 定义、所有权与数据流 <a class="header-anchor" href="#_1-定义、所有权与数据流" aria-label="Permalink to &quot;1. 定义、所有权与数据流&quot;">​</a></h2><p>按领域组织把同一业务能力的 UI、用例、类型、测试和适配器放在可识别模块中。目录反映业务语言和依赖边界，而不是把所有 components、hooks、services 堆成全局技术层。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A0[&quot;应用入口&quot;] --&gt; A1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A1[&quot;领域模块公开 API&quot;] --&gt; A2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A2[&quot;用例与组件&quot;] --&gt; A3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A3[&quot;领域端口&quot;] --&gt; A4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A4[&quot;基础设施适配&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>按业务领域组织把同一能力的组件、用例、类型、端口和测试放进一个可识别模块。模块通过公开入口协作，目录反映业务变化与所有权，不是把技术文件简单换个文件夹。</p><h2 id="_2-关键机制" tabindex="-1">2. 关键机制 <a class="header-anchor" href="#_2-关键机制" aria-label="Permalink to &quot;2. 关键机制&quot;">​</a></h2><h3 id="_2-1-领域识别" tabindex="-1">2.1 领域识别 <a class="header-anchor" href="#_2-1-领域识别" aria-label="Permalink to &quot;2.1 领域识别&quot;">​</a></h3><p>按订单、账单、身份等业务能力及变化共振切分。</p><p>若边界缺失，按页面截图随意切模块。</p><p>验证：变更历史聚类。</p><h3 id="_2-2-公开入口" tabindex="-1">2.2 公开入口 <a class="header-anchor" href="#_2-2-公开入口" aria-label="Permalink to &quot;2.2 公开入口&quot;">​</a></h3><p>模块只从 index 导出允许依赖的契约。</p><p>若边界缺失，深层导入内部文件。</p><p>验证：lint 禁止越界。</p><h3 id="_2-3-内部凝聚" tabindex="-1">2.3 内部凝聚 <a class="header-anchor" href="#_2-3-内部凝聚" aria-label="Permalink to &quot;2.3 内部凝聚&quot;">​</a></h3><p>类型、用例和测试靠近共同变化原因。</p><p>若边界缺失，技术目录让一次功能跨十处。</p><p>验证：统计变更文件跨度。</p><h3 id="_2-4-共享内核" tabindex="-1">2.4 共享内核 <a class="header-anchor" href="#_2-4-共享内核" aria-label="Permalink to &quot;2.4 共享内核&quot;">​</a></h3><p>只放稳定跨域值对象和协议。</p><p>若边界缺失，shared 变成无主杂物箱。</p><p>验证：每项有 owner 与消费者。</p><h3 id="_2-5-跨域协作" tabindex="-1">2.5 跨域协作 <a class="header-anchor" href="#_2-5-跨域协作" aria-label="Permalink to &quot;2.5 跨域协作&quot;">​</a></h3><p>通过公开命令、事件或只读投影。</p><p>若边界缺失，直接读另一个域 store。</p><p>验证：依赖图审计。</p><h3 id="_2-6-路由组合" tabindex="-1">2.6 路由组合 <a class="header-anchor" href="#_2-6-路由组合" aria-label="Permalink to &quot;2.6 路由组合&quot;">​</a></h3><p>应用层组合领域路由，不让领域反向依赖 app。</p><p>若边界缺失，模块导入根路由。</p><p>验证：构建层级检查。</p><h3 id="_2-7-数据边界" tabindex="-1">2.7 数据边界 <a class="header-anchor" href="#_2-7-数据边界" aria-label="Permalink to &quot;2.7 数据边界&quot;">​</a></h3><p>每个域拥有 query key 和 DTO 映射。</p><p>若边界缺失，全局 api.ts 理解全部业务。</p><p>验证：适配器归属清晰。</p><h3 id="_2-8-测试边界" tabindex="-1">2.8 测试边界 <a class="header-anchor" href="#_2-8-测试边界" aria-label="Permalink to &quot;2.8 测试边界&quot;">​</a></h3><p>领域用例可用内存端口独立运行。</p><p>若边界缺失，只能启动整站测试。</p><p>验证：模块测试速度与隔离。</p><h3 id="_2-9-团队所有权" tabindex="-1">2.9 团队所有权 <a class="header-anchor" href="#_2-9-团队所有权" aria-label="Permalink to &quot;2.9 团队所有权&quot;">​</a></h3><p>目录与评审责任一致。</p><p>若边界缺失，跨团队共享文件频繁冲突。</p><p>验证：CODEOWNERS 统计。</p><h3 id="_2-10-渐进迁移" tabindex="-1">2.10 渐进迁移 <a class="header-anchor" href="#_2-10-渐进迁移" aria-label="Permalink to &quot;2.10 渐进迁移&quot;">​</a></h3><p>从高变更用例建立新边界，旧代码经兼容入口调用。</p><p>若边界缺失，一次性搬目录制造风险。</p><p>验证：逐模块依赖收敛。</p><h2 id="_3-从变更历史识别领域边界" tabindex="-1">3. 从变更历史识别领域边界 <a class="header-anchor" href="#_3-从变更历史识别领域边界" aria-label="Permalink to &quot;3. 从变更历史识别领域边界&quot;">​</a></h2><p>抽取最近十个需求，记录每次同时修改的规则、组件和接口。退款资格、退款理由和退款状态经常共同变化，应归入 refunds；通用 Button 因品牌和无障碍变化而修改，属于 shared-ui。页面相邻不代表同领域，复用同一个 DTO 也不代表共享所有权。</p><h2 id="_4-一个领域模块的内部方向" tabindex="-1">4. 一个领域模块的内部方向 <a class="header-anchor" href="#_4-一个领域模块的内部方向" aria-label="Permalink to &quot;4. 一个领域模块的内部方向&quot;">​</a></h2><ol><li><p>domain 公开 types、commands、queries 和必要 UI，内部 DTO 与 reducer 不导出。</p></li><li><p>application 用例编排领域规则并依赖本模块定义的端口。</p></li><li><p>infrastructure 适配 HTTP 或 SDK 并把 DTO 转领域对象。</p></li><li><p>ui 调用用例、消费领域投影，不直接拼接 API URL。</p></li><li><p>模块 index 只导出承诺兼容的入口，内部文件使用相对导入避免 barrel 回环。</p></li></ol><h2 id="_5-应用案例一-退款领域" tabindex="-1">5. 应用案例一：退款领域 <a class="header-anchor" href="#_5-应用案例一-退款领域" aria-label="Permalink to &quot;5. 应用案例一：退款领域&quot;">​</a></h2><ol><li><p>建立 refunds/application、domain、infrastructure、ui 和 index。</p></li><li><p>把 canRefund 的证据与规则移入退款域，而不是订单 Badge。</p></li><li><p>Order 页面只从 refunds 公开入口导入 RefundPanel。</p></li><li><p>RefundGateway 的内存实现运行资格和提交用例测试。</p></li><li><p>改变后端退款 DTO 时只修改适配器与其契约 fixture。</p></li></ol><p>结果：规则修改集中在退款模块。</p><p>失败分支：若 refunds 导入 orders 内部 reducer，边界仍未成立。</p><h2 id="_6-应用案例二-身份与权限" tabindex="-1">6. 应用案例二：身份与权限 <a class="header-anchor" href="#_6-应用案例二-身份与权限" aria-label="Permalink to &quot;6. 应用案例二：身份与权限&quot;">​</a></h2><ol><li><p>identity 提供当前主体与会话生命周期。</p></li><li><p>authorization 把 capability 作为稳定只读查询，不暴露角色字符串。</p></li><li><p>订单域声明 order.refund 等能力并决定业务操作组合。</p></li><li><p>应用层在登录/登出时协调两个域和缓存清理。</p></li><li><p>直接调用服务端接口仍执行授权，前端 capability 只控制体验。</p></li></ol><p>结果：页面不散落角色字符串。</p><p>失败分支：前端能力判断不替代服务端授权。</p><h2 id="_7-typescript-核心实现" tabindex="-1">7. TypeScript 核心实现 <a class="header-anchor" href="#_7-typescript-核心实现" aria-label="Permalink to &quot;7. TypeScript 核心实现&quot;">​</a></h2><p>下面代码通过领域公开入口暴露用例和类型，模块内部保留 UI、规则与适配器。消费者只能导入入口，目录移动测试用来确认外部代码没有依赖内部文件。</p><div class="language-tsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// refunds/index.ts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { RefundPanel } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;./ui/RefundPanel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { requestRefund } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;./application/requestRefund&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { RefundGateway, RefundReason } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;./application/ports&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 其他模块只能从公开入口导入：</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { RefundPanel } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;../refunds&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>模块类型能描述公开 API，却不能阻止深层路径导入或共享目录反向依赖业务。需要用 exports、lint 边界和构建图执行规则，并在运行测试中验证适配器输入。</p><h2 id="_8-方案选择" tabindex="-1">8. 方案选择 <a class="header-anchor" href="#_8-方案选择" aria-label="Permalink to &quot;8. 方案选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>适用条件</th><th>成本与限制</th></tr></thead><tbody><tr><td>按技术类型</td><td>小型原型、模块少</td><td>增长后一次功能跨目录</td></tr><tr><td>按页面</td><td>页面高度独立</td><td>共享领域规则易复制</td></tr><tr><td>按领域</td><td>业务持续演进、多人协作</td><td>需维护公开 API 和跨域协议</td></tr></tbody></table><p>领域边界应依据业务语言、共同变化和团队所有权，而不是页面相邻或文件类型。只有真正跨领域稳定的能力才进入 shared，并为其定义更严格的兼容责任。</p><h2 id="_9-调试与失败注入" tabindex="-1">9. 调试与失败注入 <a class="header-anchor" href="#_9-调试与失败注入" aria-label="Permalink to &quot;9. 调试与失败注入&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>检查</th><th>修正</th></tr></thead><tbody><tr><td>一次需求改十目录</td><td>是否按技术类型分散</td><td>建立领域垂直切片</td></tr><tr><td>shared 无人维护</td><td>是否缺 owner</td><td>移回领域或指定内核</td></tr><tr><td>跨域深层导入</td><td>缺少 exports 规则</td><td>公开入口加 lint</td></tr><tr><td>模块互相调用 store</td><td>协作协议不清</td><td>命令或投影</td></tr><tr><td>重复 DTO</td><td>基础设施边界散落</td><td>每域统一映射</td></tr><tr><td>循环依赖</td><td>双向业务知识</td><td>提取协调用例</td></tr><tr><td>测试只能 E2E</td><td>模块依赖具体设施</td><td>端口与内存适配</td></tr><tr><td>迁移停滞</td><td>新旧没有桥接</td><td>兼容入口与指标</td></tr></tbody></table><p>先从一次需求变更列出同时修改的文件，再检查它们是否跨越公开入口或通过 shared 偷渡领域规则，最后查看循环和发布影响。失败信号是小需求横跨多个技术目录、深层导入泛滥或领域测试必须启动整站；用变更耦合、依赖图和模块级测试验证边界。</p><h2 id="_10-性能、安全与运维边界" tabindex="-1">10. 性能、安全与运维边界 <a class="header-anchor" href="#_10-性能、安全与运维边界" aria-label="Permalink to &quot;10. 性能、安全与运维边界&quot;">​</a></h2><ul><li>模块入口控制可见 API。</li><li>领域类型不直接等于后端 DTO。</li><li>共享内核保持小且有版本责任。</li><li>路由和组合根位于应用层。</li><li>权限由服务端最终执行。</li><li>构建输出检查跨模块 chunk 和包体。</li><li>变更日志记录公开契约。</li><li>依赖可视化进入 CI。</li></ul><p>生产验证至少记录一次正常路径和一次故障路径；对“按业务领域组织模块”的结论必须能关联到日志、Profile、网络记录或自动化测试。</p><h2 id="_11-与其他架构模块集成" tabindex="-1">11. 与其他架构模块集成 <a class="header-anchor" href="#_11-与其他架构模块集成" aria-label="Permalink to &quot;11. 与其他架构模块集成&quot;">​</a></h2><ul><li>单向依赖规则执行模块边界。</li><li>依赖倒置隔离基础设施。</li><li>ADR 记录争议切分。</li><li>循环检测防止边界腐化。</li></ul><p>集成时领域之间通过公开用例、事件或稳定 DTO 协作，不读取对方内部 store 和组件。迁移期间保留兼容入口并统计旧路径使用量，清零后再删除。</p><h2 id="_12-综合练习" tabindex="-1">12. 综合练习 <a class="header-anchor" href="#_12-综合练习" aria-label="Permalink to &quot;12. 综合练习&quot;">​</a></h2><p>把按 components/hooks/services 组织的订单退款功能迁移为领域模块，并保持旧入口可用。</p><h3 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h3><ul><li>[ ] 退款规则及适配器集中在 refunds。</li><li>[ ] 其他域只能从公开 index 导入。</li><li>[ ] 订单与库存协作位于上层协调器且无环。</li><li>[ ] shared 每项有明确 owner 和两个真实消费者。</li><li>[ ] 替换退款 HTTP DTO 不改页面和领域用例。</li></ul><h2 id="_13-跨领域协作的三种形式" tabindex="-1">13. 跨领域协作的三种形式 <a class="header-anchor" href="#_13-跨领域协作的三种形式" aria-label="Permalink to &quot;13. 跨领域协作的三种形式&quot;">​</a></h2><p>同步查询适合读取稳定投影，例如订单域读取“当前主体是否具有 refund capability”；它不应取得 authorization 内部 store。命令适合明确请求另一个域执行动作，并返回领域结果。事件适合已经发生的事实通知多个未知消费者，但需要事件版本、幂等和失败观测。</p><p>订单创建后立即预留库存同时需要两个域时，把用例放在 application orchestration：它依赖 OrderPort 与 InventoryPort。不要让 orders 导入 inventory 内部函数，同时又让 inventory 回调 orders。上移协调器可以保持两个领域无环。</p><p><code>shared</code> 只接受稳定且确有多个 owner 共同承诺的内容。为了消除 import 错误把 <code>OrderStatus</code> 搬进 shared，会丢失订单所有权。共享内核的每个导出都需要负责人、消费者清单和兼容策略。</p><h2 id="_14-目录与公开契约示例" tabindex="-1">14. 目录与公开契约示例 <a class="header-anchor" href="#_14-目录与公开契约示例" aria-label="Permalink to &quot;14. 目录与公开契约示例&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>  app/</span></span>
<span class="line"><span>    routes.tsx</span></span>
<span class="line"><span>    composition-root.ts</span></span>
<span class="line"><span>  domains/</span></span>
<span class="line"><span>    refunds/</span></span>
<span class="line"><span>      application/</span></span>
<span class="line"><span>        request-refund.ts</span></span>
<span class="line"><span>        ports.ts</span></span>
<span class="line"><span>      domain/</span></span>
<span class="line"><span>        refund.ts</span></span>
<span class="line"><span>        eligibility.ts</span></span>
<span class="line"><span>      infrastructure/</span></span>
<span class="line"><span>        http-refund-gateway.ts</span></span>
<span class="line"><span>      ui/</span></span>
<span class="line"><span>        refund-panel.tsx</span></span>
<span class="line"><span>      index.ts</span></span>
<span class="line"><span>  shared/</span></span>
<span class="line"><span>    ui/</span></span>
<span class="line"><span>    platform/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><p><code>refunds/index.ts</code> 只导出 <code>RefundPanel</code>、<code>requestRefund</code> 和调用方需要的公开类型。<code>http-refund-gateway.ts</code>、后端 DTO 与内部状态枚举不导出。退款模块内部也不从自己的 index 回导，否则 barrel 可能形成初始化环。</p><p>应用组合根导入 <code>RefundGateway</code> 端口与 HTTP 实现，创建用例后传给页面。若希望领域模块完全不知道 React，可让页面适配用例结果；若领域 UI 是团队承诺的公开能力，也可从模块入口导出，但仍不能让 domain 目录依赖 React。</p><h2 id="_15-切分过细与过粗的信号" tabindex="-1">15. 切分过细与过粗的信号 <a class="header-anchor" href="#_15-切分过细与过粗的信号" aria-label="Permalink to &quot;15. 切分过细与过粗的信号&quot;">​</a></h2><p>只有一个类型和一个函数、每次都与另一个模块同时修改的“领域”，可能切得过细。包含十几个互不相关用例、需要多个团队共同批准任何修改的模块，可能过粗。</p><p>可记录三个月数据：</p><ul><li>一次需求跨多少模块；</li><li>哪些文件经常共同修改；</li><li>跨模块公开 API 的变更次数；</li><li>循环依赖与例外数量；</li><li>每个模块的负责人和独立测试耗时。</li></ul><p>数据不能自动给出领域答案，但能暴露边界与真实变化不一致。重切边界时用兼容入口迁移消费者，先阻止新增深层导入，再逐步移动实现，避免一次性目录搬迁与功能修改混在同一提交。</p><h2 id="_16-模块测试与发布边界" tabindex="-1">16. 模块测试与发布边界 <a class="header-anchor" href="#_16-模块测试与发布边界" aria-label="Permalink to &quot;16. 模块测试与发布边界&quot;">​</a></h2><p>退款模块的应用测试使用内存 <code>RefundGateway</code> 覆盖资格通过、证据不足、重复请求和取消。HTTP 适配器使用契约 fixture 覆盖 DTO 转换。<code>RefundPanel</code> 只测试可访问交互和用例结果，不在组件测试里重复后端规则。</p><p>若领域模块作为独立 package 发布，<code>package.json#exports</code> 只列公开入口，类型声明也不能泄漏内部 DTO。若仍在单仓源码中，ESLint/Nx 边界规则承担同一职责。两种形式都要用一个故意深层导入的失败 fixture 证明约束真实生效。</p><p>跨模块事件需要名字、载荷 schema、版本和幂等语义。<code>refund.completed.v1</code> 表示已经发生的事实；消费者失败不能回滚退款本身。需要原子业务结果时应使用同步协调用例，而不是广播事件后假定所有消费者成功。</p><p>领域拆分也影响 bundle：只有进入退款页面才需要的复杂编辑器可以从退款公开入口动态加载；共享基础按钮不应在多个领域重复打包。构建 metafile 用于检查边界是否造成意外公共 chunk。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.typescriptlang.org/docs/handbook/2/modules.html" target="_blank" rel="noreferrer">TypeScript：Modules</a>（访问日期：2026-07-18）</li><li><a href="https://nodejs.org/api/packages.html#package-entry-points" target="_blank" rel="noreferrer">Node.js：Package entry points</a>（访问日期：2026-07-18）</li><li><a href="https://nx.dev/features/enforce-module-boundaries" target="_blank" rel="noreferrer">Nx：Enforce Module Boundaries</a>（访问日期：2026-07-18）</li><li><a href="https://vite.dev/guide/features.html" target="_blank" rel="noreferrer">Vite：Features</a>（访问日期：2026-07-18）</li></ul>`,102)])])}const b=s(t,[["render",l]]);export{u as __pageData,b as default};
